('deal-020','Versara','Sophie Martin','https://linkedin.com/in/sophie-martin-versara','seed','€2M',2000000,'France','invested',NULL,'Matilda','referral','2025-10-20','AI-powered fashion resale marketplace. Paris-based. We invested €500K in a €2M round. 50K MAU, strong unit economics, 40% MoM growth.','["fashion","marketplace","ai","sustainability","france"]'),
('deal-021',NULL,'Kai Nakamura',NULL,'pre-seed','€1M',1000000,'Germany','new',NULL,NULL,'whatsapp','2026-04-06','Stealth. No LinkedIn found. Intro via WhatsApp from a trusted angel. Claims ex-Stripe, building something in embedded insurance. Need to verify background.','["stealth","insurtech","fintech","unverified"]'),
('deal-022','Gridwise Energy','Laura Schmidt','https://linkedin.com/in/laura-schmidt-gridwise','series-a','€15M',15000000,'Germany','passed','Too large for our fund. Great company (we actually wanted to invest at seed but missed it). Congrats to them. Introduced LP connection at Lakestar.','Francesco','email','2026-02-20','Smart grid optimization using AI. Portfolio company we wish we had. €5M ARR, 80+ utility customers.','["energy","ai","cleantech","too-large","wish-we-had"]'),
('deal-023','Speakr','Max Vogel','https://linkedin.com/in/max-vogel-speakr','pre-seed','€500K',500000,'Germany','rejected','Consumer social apps are outside our thesis. High churn risk, advertising-dependent monetization. Does not match our B2B/SaaS focus.','Matilda','website','2026-03-05','Audio-based social networking app for Gen Z. Interesting concept but consumer social is not in our mandate.','["social","consumer","audio","b2c"]'),
('deal-024','Metriko','Elena Petrov','https://linkedin.com/in/elena-petrov-metriko','seed','€2.5M',2500000,'Germany','reviewing',NULL,'Matilda','referral','2026-04-01','Analytics platform for D2C brands. Replaces Google Analytics + Mixpanel with privacy-first European alternative. 150 paying brands, €80K MRR. Referred by HV Capital.','["analytics","privacy","d2c","saas","berlin"]'),
('deal-025','WunderDoc','Dr. Fabian Gross','https://linkedin.com/in/fabian-gross-wunderdoc','seed','€4M',4000000,'Germany','new',NULL,NULL,'email','2026-04-05','AI medical documentation for German hospitals. Automates Arztbriefe and clinical notes. Pilot at Charite + 3 other hospitals. Team is 2 doctors + 3 engineers.','["healthtech","ai","hospitals","documentation","berlin"]'),
('deal-026','TruckTrail','Piotr Kowalski','https://linkedin.com/in/piotr-kowalski-trucktrail','seed','€2M',2000000,'Germany','rejected','Founder based in Warsaw, company registered in Berlin but no real presence. Team fully remote in Poland. Outside our requirement for DACH-based teams.','Francesco','linkedin','2026-02-10','Freight matching platform for CEE trucking. Interesting market but team location is a concern for our thesis.','["logistics","marketplace","poland","remote"]'),
('deal-027','Aurea Labs','Charlotte Moreau','https://linkedin.com/in/charlotte-moreau-aurea','seed','€3M',3000000,'France','reviewing',NULL,'Francesco','referral','2026-03-18','AI-powered quality control for food manufacturing. Computer vision for production lines. 8 factories in France, expanding to Germany. Referred by Partech.','["foodtech","ai","manufacturing","computer-vision","france"]'),
('deal-028',NULL,'David Chen','https://linkedin.com/in/david-chen-ml','pre-seed','€800K',800000,'UK','new',NULL,NULL,'referral','2026-04-04','Stealth. London-based, ex-Google Brain. Building ML infrastructure tooling. Strong pedigree. UK is borderline for our geo focus, need to discuss at IC.','["stealth","ai","ml-infra","uk","ex-google"]'),
('deal-029','Mieter.ai','Nina Bauer','https://linkedin.com/in/nina-bauer-mieter-ai','pre-seed','€700K',700000,'Germany','reviewing',NULL,'Matilda','event','2026-03-22','AI tenant screening and rental management for German landlords. Automates Schufa checks, document verification, lease generation. Met at Berlin Startup Night.','["proptech","ai","germany","b2b","regulatory"]'),
('deal-030','Fundcraft','Robert Zimmermann','https://linkedin.com/in/robert-zimmermann-fundcraft','seed','€3M',3000000,'Germany','passed','Conflict of interest. Product directly competes with a tool we use internally. Would create awkward dynamics with our LPs who also use the competitor.','Francesco','email','2026-01-30','Fund administration software for European VCs. Ironic that we would have loved this as a product but cannot invest due to conflicts.','["fintech","vc-tools","conflict","saas"]');

-- Seed data: 13 meetings
INSERT OR REPLACE INTO meetings (id, deal_id, title, date, participants, type, key_decisions, action_items, summary) VALUES
('mtg-001','deal-001','IC Discussion: Solaris Health Seed','2026-04-01','["Francesco","Matilda","Julian"]','ic-discussion','["Proceed with deeper due diligence on Solaris Health","Request customer reference calls from 3 hospitals","Need to understand unit economics better before committing"]','["Francesco to schedule follow-up call with Anna Bergmann for financials deep dive","Matilda to check if any LP connections in hospital networks for references","Julian to run competitive analysis on digital health marketplaces in DACH"]','Team is cautiously optimistic about Solaris Health. The 15k MAU is impressive for a health marketplace at seed. Main concern is regulatory complexity in DACH healthcare. Point Nine referral adds credibility. Francesco noted that the founder''s previous experience at Doctolib is a strong signal. Need to verify the claimed 30% month-over-month growth before making a decision. Timeline: aim to have a decision by end of next week.'),
('mtg-002','deal-003','Founder Call: Claire Dubois (DataForge AI)','2026-02-20','["Francesco","Claire Dubois"]','founder-call','["Pass on DataForge AI despite strong team","Market saturation is the primary concern"]','["Francesco to send a thoughtful rejection email","Keep Claire in network for potential future opportunities"]','30-minute call with Claire. She presented well, showing strong technical depth and a clear vision for AI data pipelines. Revenue is at €400K ARR with 3x YoY growth. However, when pushed on differentiation from Scale AI, Snorkel, and other synthetic data players, the answer was primarily better UX and European data residency. That is not enough moat for a Series A at €8M. We counted at least 12 well-funded competitors. Team quality is the only standout, but team alone cannot overcome market saturation at this stage. Francesco will send a kind rejection and keep the relationship warm.'),
('mtg-003','deal-005','IC Decision: Carbonfarm Investment','2025-11-15','["Francesco","Matilda","Julian"]','ic-discussion','["Invest €750K in Carbonfarm''s €3M seed round","Take board observer seat","Connect portfolio companies for potential partnerships"]','["Francesco to finalize term sheet by end of week","Legal to start due diligence process","Matilda to intro to Terraverde for potential supply chain synergies"]','Unanimous decision to invest. Tobias is an exceptional founder with deep domain expertise in carbon markets. The satellite + AI approach to carbon credit verification is genuinely differentiated. EU CBAM regulation creates massive tailwind. Technical due diligence confirmed the ML model accuracy at 94%. First-mover advantage in European agricultural carbon, which is underserved. Risk factors: regulatory dependency and long sales cycles with agricultural companies. Mitigation: Tobias already has 5 LOIs from major agricultural cooperatives.'),
('mtg-004','deal-007','Partner Sync: Stealth AI Infra (Sarah Kim)','2026-04-02','["Francesco","Matilda"]','partner-sync','["Fast-track this deal, schedule founder meeting within 48 hours","This is a top-priority deal for Q2"]','["Francesco to reach out to Sarah Kim for a call tomorrow","Check with Cherry Ventures on co-invest appetite","Prepare competitive landscape memo on AI agent infrastructure"]','Quick sync on the Sarah Kim stealth deal. Cherry Ventures referred her and the signal is very strong. Ex-DeepMind for 6 years, published papers on agent architectures. What she is building sounds like infrastructure for AI agent orchestration, which is one of the hottest spaces right now. Round is competitive with multiple term sheets expected. Francesco thinks we need to move within a week or we lose this. Matilda flagged that we should be careful about valuation in this space given recent corrections, but agreed the founder quality warrants urgency.'),
('mtg-005','deal-010','IC Discussion: Kassenzone Series A','2026-01-25','["Francesco","Matilda","Julian"]','ic-discussion','["Pass due to round size exceeding our fund capacity","Make warm introductions to larger funds"]','["Francesco to intro Felix Weber to Headline and HV Capital","Track Kassenzone for potential follow-on if we raise Fund II"]','Painful pass. Kassenzone is exactly the type of company we want to back: German e-commerce infrastructure, strong metrics (€2M ARR, 4x growth), great founder. But at €12M round size, our max check of €1.5M would give us less than 10% of the round, and they want a lead investor. We cannot lead at this size with our current fund. Francesco will make introductions to Headline (who he knows well) and HV Capital. This deal reinforces the case for raising a larger Fund II.'),
('mtg-006','deal-009','Founder Call: Emilie Laurent (Lumora)','2026-03-28','["Matilda","Emilie Laurent"]','founder-call','["Very promising, proceed to full due diligence","Schedule product demo and customer calls"]','["Matilda to schedule product demo next week","Request 3 customer references from real estate agencies","Financial model review with Julian"]','Excellent 45-minute call with Emilie. She previously led product at Matterport and understands the 3D/visual space deeply. Lumora''s virtual staging product is genuinely 10x cheaper than physical staging while producing comparable quality. The €180K MRR is strong for a seed-stage company in France. Impressive retention: 92% of agencies that try it continue using it monthly. The AI model was trained on 500K+ real estate images. Expansion plan to Germany makes sense given similar market dynamics. One concern: dependency on real estate market cycles. Matilda is quite bullish.'),
('mtg-007','deal-014','Founder Call: Dr. Yuki Tanaka (Aidente)','2026-04-02','["Francesco","Dr. Yuki Tanaka"]','founder-call','["Strong candidate, schedule IC discussion","Need to verify CE marking documentation"]','["Francesco to schedule IC meeting for next Monday","Request CE marking certificates and clinical trial data","Connect with Charite contact for reference"]','Dr. Tanaka is incredibly impressive. PhD in medical imaging from ETH Zurich, 5 years at Charite research. The dental X-ray AI detects 14 conditions with 97% accuracy, which exceeds most radiologists. Already CE-marked (huge barrier to entry for competitors). 80 dental practices in the pilot, converting at 60% to paid. The €3M round is reasonable for the traction. Earlybird referred this and they are considering co-investing. Main risk is the long enterprise sales cycle in healthcare, but the Charite partnership de-risks early distribution significantly.'),
('mtg-008','deal-019','IC Discussion: Pliant Carbon Seed','2026-04-04','["Francesco","Matilda","Julian"]','ic-discussion','["Proceed to term sheet for Pliant Carbon","Aim for €500K check in €3M round","Condition on CSRD compliance certification verification"]','["Francesco to draft term sheet by Wednesday","Julian to verify CSRD compliance claims with external auditor","Matilda to check for overlap with Carbonfarm portfolio company"]','Strong conviction from the team. CSRD compliance is becoming mandatory for 50K+ European companies starting 2026, creating enormous demand. Pliant Carbon''s automation approach reduces compliance costs by 70% compared to traditional consultants. The €50K MRR from 20 Mittelstand customers validates product-market fit. Jens previously built and sold an ERP module, so he understands enterprise sales. La Famiglia referral is a good signal. Only concern: potential overlap with our Carbonfarm investment, but after discussion, the products are actually complementary (Carbonfarm = measurement, Pliant = reporting). Green light to proceed.'),
('mtg-009','deal-024','Founder Call: Elena Petrov (Metriko)','2026-04-03','["Matilda","Elena Petrov"]','founder-call','["Interesting product, need to understand competitive positioning vs Plausible and Fathom","Schedule technical deep-dive"]','["Matilda to schedule technical architecture review","Request competitive differentiation one-pager from Elena","Check if any D2C brands in our network could be reference customers"]','Elena is ex-Amplitude, deeply understands the analytics space. Metriko is positioning as the privacy-first European analytics stack for D2C brands. Unlike Plausible (which is simple web analytics), Metriko offers full product analytics, cohort analysis, and attribution. 150 paying brands is impressive traction. The €80K MRR suggests healthy ARPU. Elena''s pitch: post-cookie world + European privacy regulations = massive demand for a European-built analytics tool that does not rely on third-party cookies. Makes sense. Need to dig deeper on technical differentiation from Mixpanel''s European hosting option.'),
('mtg-010','deal-015','IC Discussion: FleetPulse Series A Pass','2026-02-05','["Francesco","Matilda","Julian"]','ic-discussion','["Pass on FleetPulse due to valuation concerns","Good company but asking too much"]','["Francesco to send rejection with clear valuation feedback","Revisit if they adjust expectations or hit €3M+ ARR"]','Quick discussion. FleetPulse is a solid product with real traction in logistics fleet management. The predictive maintenance feature using IoT sensor data is genuinely differentiated. However, €50M pre-money on €1.5M ARR is a 33x revenue multiple, which is excessive for a Series A in this space. Comparable companies (Geotab, Samsara) had more reasonable multiples at similar stages. Thomas seems influenced by 2021-era valuations. Francesco will send honest feedback suggesting they either grow into the valuation or adjust. We would reconsider at a 20-25x multiple.'),
('mtg-011','deal-029','Founder Call: Nina Bauer (Mieter.ai)','2026-03-25','["Matilda","Nina Bauer"]','founder-call','["Promising early-stage company, schedule product demo","Regulatory angle could be a strong moat"]','["Matilda to try the product as a test landlord","Nina to share Schufa integration partnership details","Check with LP who owns rental properties for market feedback"]','Nina comes from a legal tech background (3 years at LegalZoom Germany). She identified the tenant screening pain point from personal experience as a landlord. Mieter.ai automates the entire rental application process: Schufa checks, income verification, document collection, and lease generation. The regulatory angle is interesting since German rental law is complex and frequently updated. AI keeps up with legal changes automatically. Pre-seed at €700K is very reasonable. 30 landlords managing 200+ units are using it in beta. The main question is whether this can scale beyond individual landlords to property management companies.'),
('mtg-012','deal-027','Founder Call: Charlotte Moreau (Aurea Labs)','2026-03-22','["Francesco","Charlotte Moreau"]','founder-call','["High conviction deal, fast-track to IC","Computer vision for food QC is a massive market"]','["Francesco to schedule IC for Monday","Request factory visit at one of the 8 pilot sites","Due diligence on food safety regulatory requirements"]','Charlotte is ex-Danone R&D, spent 8 years in food manufacturing. She built Aurea Labs to solve the quality control inspection problem she saw daily: manual visual inspection by tired workers missing defects. Their computer vision system runs on edge devices at the production line and catches defects in real-time with 99.2% accuracy. 8 factories in France are piloting (including one Danone facility). The expansion to Germany is logical because German food manufacturing is the largest in Europe. Partech referred this and they are leading the round. We could co-invest at €500K-750K. Very strong deal.'),
('mtg-013','deal-004','Founder Call: Leonie Hartmann (Kita Stack)','2026-03-24','["Matilda","Leonie Hartmann"]','founder-call','["Proceed with deeper analysis of Kita market size in Germany","Regulatory tailwinds from digitization mandates are a plus"]','["Matilda to research total addressable market for Kita management software","Schedule call with Berlin Jugendamt contact for regulatory perspective","Leonie to share product demo recording"]','Leonie is a former Kita director turned founder, so she has firsthand experience with the pain. Germany has 57,000 Kitas, most using paper or basic Excel for operations. Berlin recently mandated digital record-keeping, and other states are following. 45 Kitas onboarded in just 4 months shows strong pull from the market. Revenue is small (€8K MRR) but growing fast. The pre-seed ask of €750K is reasonable. Main question: can she build a sales team to reach Kitas outside of Berlin''s word-of-mouth network? Product looks solid from the screenshots she shared.');
